function App() {
  const courses = ["React cơ bản", "JS nâng cao", "HTML CSS"];

  return (
    <div>
      <h1>QUẢN LÝ KHÓA HỌC</h1>

      <CourseList courses={courses} />
    </div>
  );
}

export default App;
